 1	import * as React from 'react';
 2	import classNames from 'classnames';
 3	import {
 4	  DescriptionList,
 5	  DescriptionListDescription,
 6	  DescriptionListGroup,
 7	  DescriptionListTerm,
 8	} from '@patternfly/react-core';
 9	import PipelineResourceRef from './PipelineResourceRef';
10	
11	import './DynamicResourceLinkList.scss';
12	
13	export type ResourceModelLink = {
14	  resourceKind: string;
15	  name: string;
16	  qualifier?: string;
17	  disableLink?: boolean;
18	  namespace?: string;
19	  resourceApiVersion?: string;
20	};
21	
22	type DynamicResourceLinkListProps = {
23	  links: ResourceModelLink[];
24	  namespace: string;
25	  title?: string;
26	  removeSpaceBelow?: boolean;
27	};
28	
29	const DynamicResourceLinkList: React.FC<DynamicResourceLinkListProps> = ({
30	  links = [],
31	  namespace,
32	  title,
33	  removeSpaceBelow,
34	}) => {
35	  if (links.length === 0) {
36	    return null;
37	  }
38	  return (
39	    <div
40	      className={classNames('odc-dynamic-resource-link-list', {
41	        'odc-dynamic-resource-link-list--addSpaceBelow': !removeSpaceBelow,
42	      })}
43	    >
44	      <DescriptionList>
45	        <DescriptionListGroup>
46	          {title && <DescriptionListTerm>{title}</DescriptionListTerm>}
47	          <DescriptionListDescription>
48	            {links.map(
49	              ({
50	                name,
51	                resourceKind,
52	                qualifier = '',
53	                disableLink = false,
54	                namespace: namespaceForTask,
55	                resourceApiVersion,
56	              }) => {
57	                let linkName = qualifier;
58	                if (qualifier?.length > 0 && name !== qualifier) {
59	                  linkName += ` (${name})`;
60	                }
61	                return (
62	                  <div key={`${resourceKind}/${linkName}`}>
63	                    <PipelineResourceRef
64	                      resourceKind={resourceKind}
65	                      resourceName={name}
66	                      displayName={linkName}
67	                      namespace={namespaceForTask || namespace}
68	                      disableLink={disableLink}
69	                      resourceApiVersion={resourceApiVersion}
70	                    />
71	                  </div>
72	                );
73	              },
74	            )}
75	          </DescriptionListDescription>
76	        </DescriptionListGroup>
77	      </DescriptionList>
78	    </div>
79	  );
80	};
81	
82	export default DynamicResourceLinkList;

